<?php
namespace App\Http\Controllers;use App\Models\{Permission,PermissionAuditLog,RolePermission,User,UserPermission};use Illuminate\Http\{JsonResponse,Request};use Illuminate\Support\Facades\DB;use Illuminate\Validation\Rule;
class PermissionController{public function index():JsonResponse{return response()->json(Permission::orderBy('group')->orderBy('name')->get()->groupBy('group'));}public function roles():JsonResponse{$rows=RolePermission::with('permission')->get()->groupBy('role');return response()->json(collect(['admin','technician','accountant','custom'])->mapWithKeys(fn($r)=>[$r=>['role'=>$r,'permissions'=>($rows[$r]??collect())->pluck('permission.key')->values()]]));}public function user(User $user):JsonResponse{$d=RolePermission::where('role',$user->role)->pluck('permission_id')->flip();$o=$user->permissionOverrides()->get()->keyBy('permission_id');return response()->json(['user'=>$this->safe($user),'permissions'=>Permission::orderBy('group')->orderBy('name')->get()->map(fn($p)=>['id'=>$p->id,'key'=>$p->key,'name'=>$p->name,'group'=>$p->group,'description'=>$p->description,'role_default'=>$d->has($p->id),'user_override'=>$o->has($p->id)?$o[$p->id]->allowed:null,'effective'=>$o->has($p->id)?$o[$p->id]->allowed:$d->has($p->id)])]);}public function updateUser(Request $r,User $user):JsonResponse{$x=$r->validate(['permissions'=>['required','array'],'permissions.*.key'=>['required','exists:permissions,key'],'permissions.*.allowed'=>['required','boolean']]);DB::transaction(function()use($r,$user,$x){$d=RolePermission::where('role',$user->role)->pluck('permission_id')->flip();foreach($x['permissions'] as $item){$p=Permission::where('key',$item['key'])->firstOrFail();$old=$user->hasPermission($p->key);if((bool)$item['allowed']===$d->has($p->id))UserPermission::where(['user_id'=>$user->id,'permission_id'=>$p->id])->delete();else UserPermission::updateOrCreate(['user_id'=>$user->id,'permission_id'=>$p->id],['allowed'=>$item['allowed']]);if($old!==(bool)$item['allowed'])PermissionAuditLog::create(['changed_by_user_id'=>$r->user()->id,'affected_user_id'=>$user->id,'permission_key'=>$p->key,'old_value'=>$old,'new_value'=>$item['allowed'],'action'=>'permission.changed']);}$this->guard();});return $this->user($user->fresh());}public function updateRole(Request $r,User $user):JsonResponse{$x=$r->validate(['role'=>['required',Rule::in(['admin','technician','accountant','custom'])]]);$old=$user->role;DB::transaction(function()use($r,$user,$x,$old){$user->update(['role'=>$x['role']]);$user->permissionOverrides()->delete();$this->guard();PermissionAuditLog::create(['changed_by_user_id'=>$r->user()->id,'affected_user_id'=>$user->id,'action'=>'role.changed','metadata'=>['old_role'=>$old,'new_role'=>$x['role']]]);});return $this->user($user->fresh());}public function audit():JsonResponse{return response()->json(PermissionAuditLog::latest()->limit(250)->get());}private function guard():void{$n=User::where('role','admin')->where('is_active',true)->get()->filter(fn($u)=>$u->hasPermission('users.permissions.manage')&&$u->hasPermission('users.roles.manage'))->count();abort_if($n<1,422,'The system must retain an active administrator with role and permission management access.');}private function safe(User $u):array{return['id'=>$u->id,'name'=>$u->name,'email'=>$u->email,'role'=>$u->role,'is_active'=>$u->is_active,'effective_permissions'=>$u->getEffectivePermissions(),'permission_overrides'=>$u->getPermissionOverrides(),'updated_at'=>$u->updated_at];}}
